SELECT cccr.*, cct.tabulation_id, cct.module_id, cct.module_type, w.waybill_number, w.container_number, v.vehicle_number, d.driver_name, ccc.cost_type, ccc.category_name FROM t_car_cost_tabulation cct LEFT JOIN t_waybill w ON cct.waybill_id = w.waybill_id LEFT JOIN t_vehicle v ON cct.vehicle_id = v.vehicle_id LEFT JOIN t_driver d ON cct.driver_id = d.driver_id LEFT JOIN t_car_cost_category ccc ON cct.category_id = ccc.category_id LEFT JOIN t_car_cost_cash_receive cccr ON cct.module_id = cccr.cash_receive_id
cct.tabulation_id IN
#{item}
